VALUES
  ('diplomatic-a3078d07-moex-00596', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-7f4830a9', 'sub-diplomatic-a3078d07-03', NULL, 'single_choice', '1921年11月華盛頓會議召開，由美、英兩國主導，召開該會議的主要目的為何？', '["1919年《凡爾賽和約》未獲美國國會批准，美國希望解決日本在山東的特權問題", "因為蘇聯革命成功，英國欲藉此會議強化與日本的同盟關係，以便繼續聯日抗俄", "為了對抗新興的蘇聯，英美鼓勵日本建設海軍，增加日本的艦隊數量", "會中各國簽訂《九國公約》，保證中國領土主權完整，為日本在華特權地位提供了護身符"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00597', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-7f4830a9', 'sub-diplomatic-a3078d07-03', NULL, 'single_choice', '清朝簽訂的對外條約當中，那一個丟失的領土最多？', '["尼布楚條約", "璦琿條約", "北京條約", "南京條約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00598', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-7f4830a9', 'sub-diplomatic-a3078d07-03', NULL, 'single_choice', '關於1899年美國的「門戶開放」（OpenDoor）政策，下列敘述何者正確？', '["英國希望中國遭到瓜分，因此不支持美國的門戶開放政策", "美國主張門戶開放政策，反映其擴張主義的意圖", "美國國務卿門羅（JamesMonroe）在光緒25年（1898年）通牒各國，要求確保各國在華平等的 商業機會", "美國曾多次動用武力，在中國捍衛「門戶開放」政策"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00599', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '有關民主原則，下列敘述何者錯誤？', '["我國憲政體制係採直接民主制", "我國之主權屬於全體國民", "人民行使國家主權的方式，多係透過投票的方式為之", "原則上以多數決定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00600', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '憲法及增修條文關於「軍人」之規定，下列敘述何者錯誤？', '["現役軍人不得兼任文官", "現役軍人應受軍事審判", "國家應對軍人退役後之就學、就業予以保障", "全國陸海空軍應超出黨派"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00601', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '依司法院釋字第756號解釋意旨，關於憲法秘密通訊自由，下列敘述何者錯誤？', '["受刑人在監禁期間，人身自由遭受限制，惟其秘密通訊自由等基本權利，仍受憲法之保障", "監獄長官閱讀受刑人發受書信，涉及對秘密通訊自由核心內涵之干預", "監獄長官為確認有無夾帶違禁品而檢查受刑人書信，並不當然影響通訊內容之秘密性", "監獄長官令受刑人刪除書信部分內容後再發出，如以法律或法律具體明確授權之命令定之，即為憲法所許"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00602', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '依司法院大法官解釋，若法律規定國家對宗教之監督僅適用於佛、道教，未對其他宗教為相同之限制，該 法律規定是否合憲？', '["違憲，因為宗教自由乃是不得以法律限制之基本權", "違憲，因為宗教自由之限制乃是內政部之行政保留事項", "違憲，因為違反宗教中立原則與宗教平等原則", "合憲，因為國家對宗教自由得以法律為必要之限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00603', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '關於憲法平等權，下列何者尚非司法院大法官解釋曾闡述之內涵？', '["對相同事物為差別待遇而無正當理由", "所採取分類與規範目的之達成間是否具一定關聯性", "是否以促進社會多元化為規範目的", "對於不同事物未為合理之差別待遇"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00604', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '下列何者不屬於訴訟權之保障範圍？', '["裁判應妥速進行，不得耗時過久", "訴訟費用不得過高，超出人民可得負擔之程度", "所有訴訟程序，均應採取三級三審制", "人民提起之行政訴訟，應得請求暫時權利保護"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00605', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '有關憲法未明文列舉之權利，下列敘述何者正確？', '["不受保障", "修憲後方得保障", "不妨害社會秩序公共利益者，受憲法保障", "不妨害國家主權者，受憲法保障"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL)
